import java.util.Arrays;

public class Solution {
    public static long solve(long[] piles) {
        Arrays.sort(piles);
        long sum = 0;
        int n = piles.length;
        for (int i = 0; i < n; i += 3) {
            sum += piles[i + 1];
        }
        return sum;
    }
}
